class Client:
    def __init__(self, server_address):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.connect(server_address)

    def send_position(self, x, y):
        encrypted_data = cipher_suite.encrypt(pickle.dumps(('update_position', 'player1', x, y))).decode('utf-8')
        self.server_socket.send(encrypted_data.encode('utf-8'))

    def receive_positions(self):
        data = self.server_socket.recv(1024)
        decrypted_data = cipher_suite.decrypt(data).decode('utf-8')
        return pickle.loads(decrypted_data)

